import { createPortal } from 'react-dom';
import { ArrowRight, Clapperboard, Video, X } from 'lucide-react';

export type ShotGroupMenuState = {
  x: number;
  y: number;
  shotId: string;
  shotName: string;
  clipIds: string[];
  rowId: string;
  trackId: string;
  hasFinalVideo: boolean;
  mode?: 'images' | 'video';
} | null;

interface ShotGroupContextMenuProps {
  menu: ShotGroupMenuState;
  menuRef: React.RefObject<HTMLDivElement | null>;
  closeMenu: () => void;
  onNavigate?: (shotId: string) => void;
  onGenerateVideo?: (shotId: string) => void;
  onSwitchToFinalVideo?: (group: { shotId: string; clipIds: string[]; rowId: string }) => void;
  onSwitchToImages?: (group: { shotId: string; rowId: string }) => void;
  onUnpinGroup?: (group: { shotId: string; trackId: string }) => void;
}

export function ShotGroupContextMenu({
  menu,
  menuRef,
  closeMenu,
  onNavigate,
  onGenerateVideo,
  onSwitchToFinalVideo,
  onSwitchToImages,
  onUnpinGroup,
}: ShotGroupContextMenuProps) {
  if (!menu) {
    return null;
  }

  const pinActions = [
    onUnpinGroup
      ? {
          key: 'unpin-shot-group',
          label: 'Remove from timeline',
          icon: X,
          onClick: () => onUnpinGroup({ shotId: menu.shotId, trackId: menu.trackId }),
        }
      : null,
  ].filter((action): action is { key: string; label: string; icon: typeof Video; onClick: () => void } => Boolean(action));
  const finalVideoActions = menu.hasFinalVideo && menu.mode !== 'video'
    ? [
      onSwitchToFinalVideo
        ? {
          key: 'switch-final-video',
          label: 'Switch to Final Video',
          icon: Video,
          onClick: () => onSwitchToFinalVideo({ shotId: menu.shotId, clipIds: menu.clipIds, rowId: menu.rowId }),
        }
        : null,
    ].filter((action): action is { key: string; label: string; icon: typeof Video; onClick: () => void } => Boolean(action))
    : [];
  const imageActions = menu.mode === 'video'
    ? [
      onSwitchToImages
        ? {
            key: 'switch-images',
            label: 'Switch to Images',
            icon: Video,
            onClick: () => onSwitchToImages({ shotId: menu.shotId, rowId: menu.rowId }),
          }
        : null,
    ].filter((action): action is { key: string; label: string; icon: typeof Video; onClick: () => void } => Boolean(action))
    : [];
  const defaultActions = [
    onNavigate
      ? { key: 'jump-to-shot', label: 'Jump to Shot', icon: ArrowRight, onClick: () => onNavigate(menu.shotId) }
      : null,
    onGenerateVideo
      ? { key: 'generate-video', label: 'Generate Video', icon: Clapperboard, onClick: () => onGenerateVideo(menu.shotId) }
      : null,
  ].filter((action): action is { key: string; label: string; icon: typeof Video; onClick: () => void } => Boolean(action));

  return createPortal(
    <div
      ref={menuRef}
      className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
      style={{ left: menu.x, top: menu.y }}
    >
      <div className="px-2 py-1 text-xs font-medium text-muted-foreground">{menu.shotName}</div>
      {pinActions.map((action) => {
        const Icon = action.icon;
        return (
          <button
            key={action.key}
            type="button"
            className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
            onClick={() => { action.onClick(); closeMenu(); }}
          >
            <Icon className="h-4 w-4" />
            {action.label}
          </button>
        );
      })}
      {pinActions.length > 0 && (finalVideoActions.length > 0 || imageActions.length > 0 || defaultActions.length > 0) && <div className="my-1 h-px bg-border" />}
      {finalVideoActions.map((action) => {
        const Icon = action.icon;
        return (
          <button
            key={action.key}
            type="button"
            className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
            onClick={() => { action.onClick(); closeMenu(); }}
          >
            <Icon className="h-4 w-4" />
            {action.label}
          </button>
        );
      })}
      {imageActions.map((action) => {
        const Icon = action.icon;
        return (
          <button
            key={action.key}
            type="button"
            className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
            onClick={() => { action.onClick(); closeMenu(); }}
          >
            <Icon className="h-4 w-4" />
            {action.label}
          </button>
        );
      })}
      {(finalVideoActions.length > 0 || imageActions.length > 0) && defaultActions.length > 0 && <div className="my-1 h-px bg-border" />}
      {defaultActions.map((action) => {
        const Icon = action.icon;
        return (
          <button
            key={action.key}
            type="button"
            className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
            onClick={() => { action.onClick(); closeMenu(); }}
          >
            <Icon className="h-4 w-4" />
            {action.label}
          </button>
        );
      })}
    </div>,
    document.body,
  );
}

import { useCallback } from 'react';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getNextClipId, type ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type {
  TimelineApplyEdit,
  TimelineDataRef,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { ShotFinalVideo } from '@/tools/video-editor/hooks/useFinalVideoAvailable';
import type { AssetRegistryEntry, PinnedShotGroup, PinnedShotImageClipSnapshot } from '@/tools/video-editor/types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface UseSwitchToFinalVideoArgs {
  applyEdit: TimelineApplyEdit;
  dataRef: TimelineDataRef;
  finalVideoMap: Map<string, ShotFinalVideo>;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
}

function getClipDuration(meta: ClipMeta, action: TimelineAction): number {
  if (typeof meta.hold === 'number' && Number.isFinite(meta.hold) && meta.hold > 0) {
    return meta.hold;
  }

  if (
    typeof meta.from === 'number'
    && typeof meta.to === 'number'
    && Number.isFinite(meta.from)
    && Number.isFinite(meta.to)
    && meta.to > meta.from
  ) {
    return Math.max(0.05, (meta.to - meta.from) / Math.max(meta.speed ?? 1, 0.01));
  }

  return Math.max(0.05, action.end - action.start);
}

function snapshotClipMeta(meta: ClipMeta): PinnedShotImageClipSnapshot['meta'] {
  return {
    clipType: meta.clipType,
    from: meta.from,
    to: meta.to,
    speed: meta.speed,
    hold: meta.hold,
    volume: meta.volume,
    x: meta.x,
    y: meta.y,
    width: meta.width,
    height: meta.height,
    cropTop: meta.cropTop,
    cropBottom: meta.cropBottom,
    cropLeft: meta.cropLeft,
    cropRight: meta.cropRight,
    opacity: meta.opacity,
    text: meta.text,
    entrance: meta.entrance,
    exit: meta.exit,
    continuous: meta.continuous,
    transition: meta.transition,
    effects: meta.effects,
  };
}

function replacePinnedGroup(
  pinnedShotGroups: NonNullable<PinnedShotGroup[]>,
  nextGroup: PinnedShotGroup,
  fallbackShotId: string,
  fallbackTrackId: string,
) {
  const existingIndex = pinnedShotGroups.findIndex((group) => (
    group.shotId === fallbackShotId
    && group.trackId === fallbackTrackId
  ));

  if (existingIndex < 0) {
    return [...pinnedShotGroups, nextGroup];
  }

  return pinnedShotGroups.map((group, index) => (index === existingIndex ? nextGroup : group));
}

export function useSwitchToFinalVideo({
  applyEdit,
  dataRef,
  finalVideoMap,
  patchRegistry,
  registerAsset,
}: UseSwitchToFinalVideoArgs) {
  const switchToFinalVideo = useCallback(({ shotId, clipIds, rowId }: { shotId: string; clipIds: string[]; rowId: string }) => {
    const finalVideo = finalVideoMap.get(shotId);
    const current = dataRef.current;
    if (!finalVideo || !current || clipIds.length === 0 || !current.rows.some((row) => row.id === rowId)) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => group.shotId === shotId && group.trackId === rowId);
    const sourceClipIds = pinnedGroup?.mode === 'images'
      ? pinnedGroup.clipIds
      : clipIds;
    const clipIdSet = new Set(sourceClipIds);
    const targetRow = current.rows.find((row) => row.id === rowId);
    if (!targetRow) {
      return;
    }

    const imageActions = targetRow.actions.filter((action) => clipIdSet.has(action.id));
    if (imageActions.length !== sourceClipIds.length) {
      return;
    }

    const startTime = Math.min(...imageActions.map((action) => action.start));
    const endTime = Math.max(...imageActions.map((action) => action.end));
    if (!Number.isFinite(startTime) || !Number.isFinite(endTime) || endTime <= startTime) {
      return;
    }

    const imageClipSnapshot = sourceClipIds.flatMap((sourceClipId) => {
      const sourceMeta = current.meta[sourceClipId];
      if (!sourceMeta) {
        return [];
      }

      return [{
        clipId: sourceClipId,
        assetKey: sourceMeta.asset,
        meta: snapshotClipMeta(sourceMeta),
      }];
    });
    if (imageClipSnapshot.length !== sourceClipIds.length) {
      return;
    }

    const assetKey = generateUUID();
    const assetEntry: AssetRegistryEntry = { file: finalVideo.location, type: 'video/mp4', generationId: finalVideo.id };
    patchRegistry(assetKey, assetEntry, finalVideo.location);
    void registerAsset(assetKey, assetEntry).catch((error) => {
      console.error('[TimelineEditor] Failed to persist final video asset:', error);
    });

    const videoClipId = getNextClipId(current.meta);
    const targetTrack = current.tracks.find((track) => track.id === rowId);
    const isManualVisualTrack = targetTrack?.kind === 'visual' && targetTrack.fit === 'manual';
    const videoMeta: ClipMeta = {
      asset: assetKey,
      track: rowId,
      clipType: 'media',
      from: 0,
      to: endTime - startTime,
      speed: 1,
      volume: 1,
      opacity: 1,
      x: isManualVisualTrack ? 100 : undefined,
      y: isManualVisualTrack ? 100 : undefined,
      width: isManualVisualTrack ? 320 : undefined,
      height: isManualVisualTrack ? 240 : undefined,
    };
    const videoAction: TimelineAction = {
      id: videoClipId,
      start: startTime,
      end: endTime,
      effectId: `effect-${videoClipId}`,
    };

    const insertionIndex = targetRow.actions.findIndex((action) => clipIdSet.has(action.id));
    const nextRows = current.rows.map((row) => {
      const remainingActions = row.actions.filter((action) => !clipIdSet.has(action.id));
      if (row.id !== rowId) {
        return remainingActions.length === row.actions.length ? row : { ...row, actions: remainingActions };
      }

      const nextActions = insertionIndex < 0
        ? [...remainingActions, videoAction]
        : [...remainingActions.slice(0, insertionIndex), videoAction, ...remainingActions.slice(insertionIndex)];
      return { ...row, actions: nextActions };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => !clipIdSet.has(id));
      const orderInsertionIndex = ids.findIndex((id) => clipIdSet.has(id));
      return orderInsertionIndex < 0
        ? [...filtered, videoClipId]
        : [...filtered.slice(0, orderInsertionIndex), videoClipId, ...filtered.slice(orderInsertionIndex)];
    });

    const nextPinnedShotGroups = replacePinnedGroup(
      existingPinnedGroups,
      {
        shotId,
        trackId: rowId,
        clipIds: [videoClipId],
        mode: 'video',
        videoAssetKey: assetKey,
        imageClipSnapshot,
      },
      shotId,
      rowId,
    );

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [videoClipId]: videoMeta },
      metaDeletes: sourceClipIds,
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const switchToImages = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
    ));
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoClipId = pinnedGroup?.clipIds[0];
    const videoActionIndex = targetRow?.actions.findIndex((action) => action.id === videoClipId) ?? -1;
    const videoAction = videoActionIndex >= 0 ? targetRow?.actions[videoActionIndex] : undefined;
    if (!pinnedGroup || !targetRow || !videoClipId || !videoAction || !pinnedGroup.imageClipSnapshot?.length) {
      return;
    }

    const restoredMetaUpdates: Record<string, ClipMeta> = {};
    let cursor = videoAction.start;
    const restoredActions = pinnedGroup.imageClipSnapshot.map((snapshot) => {
      const clipMeta: ClipMeta = {
        ...snapshot.meta,
        asset: snapshot.assetKey,
        track: rowId,
      };
      restoredMetaUpdates[snapshot.clipId] = clipMeta;
      const duration = getClipDuration(clipMeta, videoAction);
      const action: TimelineAction = {
        id: snapshot.clipId,
        start: cursor,
        end: cursor + duration,
        effectId: `effect-${snapshot.clipId}`,
      };
      cursor = action.end;
      return action;
    });

    const nextRows = current.rows.map((row) => {
      if (row.id !== rowId) {
        return row;
      }

      const remainingActions = row.actions.filter((action) => action.id !== videoClipId);
      return {
        ...row,
        actions: [

    const staleIds = new Set<string>();
    for (const group of pinnedShotGroups) {
      if (group.mode !== 'video' || !group.videoAssetKey) {
        continue;
      }

      const currentGenerationId = resolvedConfig?.registry[group.videoAssetKey]?.generationId;
      const latestFinalVideoId = finalVideoMap.get(group.shotId)?.id;
      if (!currentGenerationId || !latestFinalVideoId) {
        continue;
      }

      if (currentGenerationId !== latestFinalVideoId) {
        staleIds.add(`${group.shotId}:${group.trackId}`);
      }
    }

    return staleIds;
  }, [data?.config.pinnedShotGroups, finalVideoMap, resolvedConfig]);

  useLayoutEffect(() => {
    const wrapper = timelineWrapperRef.current;
    const nextEditArea = wrapper?.querySelector<HTMLElement>('.timeline-canvas-edit-area') ?? null;
    editAreaRef.current = nextEditArea;

    return () => {
      if (editAreaRef.current === nextEditArea) {
        editAreaRef.current = null;
      }
    };
  }, [data, editAreaRef, timelineWrapperRef]);

  const scaleCount = useMemo(() => {
    if (!data) {
      return 1;
    }

    let maxEnd = 0;
    for (const row of data.rows) {
      for (const action of row.actions) {
        maxEnd = Math.max(maxEnd, action.end);
      }
    }

    return Math.ceil((maxEnd + 20) / scale) + 1;
  }, [data, scale]);

  const thumbnailMap = useMemo<Record<string, string>>(() => {
    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    selectClip(clipId);
    setSelectedTrackId(trackId);
  }, [selectClip, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;
  const shotGroups = useShotGroups(
    data?.rows ?? [],
    shots,
    data?.config.pinnedShotGroups,
  );
  const shotGroupClipIds = useMemo(() => {
    const ids = new Set<string>();
    for (const group of shotGroups) {
      for (const clipId of group.clipIds) {
        ids.add(clipId);
      }
    }
    return ids;
  }, [shotGroups]);
  const assetGenerationMap = useMemo<Record<string, string>>(() => {
    const assets = data?.registry?.assets;
    if (!assets) {
      return EMPTY_ASSET_GENERATION_MAP;
    }

    return Object.entries(assets).reduce<Record<string, string>>((acc, [assetKey, assetEntry]) => {
      if (typeof assetEntry?.generationId === 'string' && assetEntry.generationId.length > 0) {
        acc[assetKey] = assetEntry.generationId;
      }
      return acc;
    }, {});
  }, [data?.registry?.assets]);
  const stableAssetGenerationMap = useStableValue(assetGenerationMap);
  const resolvedClipMap = useMemo(() => {
    if (!resolvedConfig) {
      return new Map<string, ResolvedTimelineClip>();
    }

    return new Map(resolvedConfig.clips.map((clip) => [clip.id, clip]));
  }, [resolvedConfig]);
  const trackMap = useMemo(() => {
    if (!resolvedConfig) {
      return new Map<string, TrackDefinition>();
    }

    return new Map(resolvedConfig.tracks.map((track) => [track.id, track]));
  }, [resolvedConfig]);

  const selectionShotCreationState = useMemo(() => {
    if (!data?.rows || !data?.meta) {
      return { canCreateShot: false, generationIds: [] as string[] };
    }

    return resolveSelectedGenerationIdsForShotCreation({
      rows: data.rows,
      meta: data.meta,
      assetGenerationMap: stableAssetGenerationMap,
      selectedClipIds,
    });
  }, [data?.rows, data?.meta, stableAssetGenerationMap, selectedClipIds]);

  const existingShotsForSelection = useMemo(() => {
    if (selectionShotCreationState.generationIds.length === 0 || !shots?.length) {
      return [] as Shot[];
    }

    return shots.filter((shot) => {
      const shotGenerationIds = new Set(
        (shot.images ?? [])
          .map((image) => image.generation_id)
          .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0),
      );

      return selectionShotCreationState.generationIds.every((generationId) => shotGenerationIds.has(generationId));
    });
  }, [shots, selectionShotCreationState.generationIds]);

  const {
    pinGroup,
    unpinGroup,
  } = usePinnedShotGroups({
    dataRef,
    applyEdit,
  });

  const handleCreateShotFromSelection = useCallback(async (): Promise<Shot | null> => {
    if (!selectionShotCreationState.canCreateShot) {
      return null;
    }

    // Determine the track from the first selected clip
    const selectedClipId = [...selectedClipIds][0];
    const trackId = selectedClipId ? data?.meta[selectedClipId]?.track : undefined;

    const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
    if (result?.shot && trackId) {
      // Auto-pin the new shot group on the timeline
      pinGroup(result.shot.id, trackId, [...selectedClipIds]);
    }
    if (result?.shot) {
      return result.shot;
    }
    return null;
  }, [createShot, data?.meta, pinGroup, selectedClipIds, selectionShotCreationState]);

  const handleGenerateVideoFromSelection = useCallback(async () => {
    if (!selectionShotCreationState.canCreateShot) {
      return;
    }

    // If exactly one existing shot already contains the selected generations, use it directly
    if (existingShotsForSelection.length === 1) {
      setVideoModalShot(existingShotsForSelection[0]);
      return;
    }

    const selectedClipId = [...selectedClipIds][0];
    const trackId = selectedClipId ? data?.meta[selectedClipId]?.track : undefined;

    const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
    if (!result?.shotId) {
      return;
    }

    if (trackId) {
      pinGroup(result.shotId, trackId, [...selectedClipIds]);
    }

    const createdShot = result.shot ?? shots?.find((shot) => shot.id === result.shotId) ?? null;
    if (createdShot) {
      setVideoModalShot(createdShot);
    }
  }, [createShot, data?.meta, existingShotsForSelection, pinGroup, selectedClipIds, selectionShotCreationState, shots]);

  const handleNavigateToShot = useCallback((shot: Shot) => {
    navigateToShot(shot, { isNewlyCreated: true });
  }, [navigateToShot]);

  const handleOpenGenerateVideo = useCallback((shot: Shot) => {
    setVideoModalShot(shot);
  }, []);

  const handleShotGroupNavigate = useCallback((shotId: string) => {
    const shot = shots?.find((s) => s.id === shotId);
    if (shot) navigateToShot(shot, { isNewlyCreated: false });
  }, [navigateToShot, shots]);

  const handleShotGroupGenerateVideo = useCallback((shotId: string) => {
    const shot = shots?.find((s) => s.id === shotId);
    if (shot) setVideoModalShot(shot);
  }, [shots]);
  const {
    switchToFinalVideo: handleSwitchToFinalVideo,
    switchToImages: handleSwitchToImages,
  } = useSwitchToFinalVideo({
    applyEdit,
    dataRef,
    finalVideoMap,
    patchRegistry,
    registerAsset,
  });
  usePinnedGroupSync({
    data,
    dataRef,
    applyEdit,
    shots,
    registerGenerationAsset,
  });

  const clientXToTime = useCallback((clientX: number): number => {
    const wrapper = timelineWrapperRef.current;
    if (!wrapper) return 0;
    const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
    const grid = editArea;
    const rect = (editArea ?? wrapper).getBoundingClientRect();
    const scrollLeft = grid?.scrollLeft ?? 0;
    return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
  }, [pixelsPerSecond, timelineWrapperRef]);

  const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
    const time = clientXToTime(clientX);
    handleSplitClipAtTime(clipId, time);
  }, [clientXToTime, handleSplitClipAtTime]);

  const getActionRender = useCallback((action: TimelineAction, _row: TimelineRow, clipWidth: number) => {
    const clipMeta = data?.meta[action.id];
    if (!clipMeta) {
      return null;
    }

    const resolvedClip = resolvedClipMap.get(action.id);
    const track = resolvedClip ? trackMap.get(resolvedClip.track) : undefined;
    const clipWidthPx = clipWidth;
    const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;
    const assetKey = clipMeta.asset;
    const audioSrc = resolveWaveformAudioSrc(resolvedClip, track);
    const isStale = assetKey ? staleAssetKeys.has(assetKey) : false;
    const isDismissed = assetKey ? dismissedAssetKeys.has(assetKey) : false;
    const isGenAsset = assetKey ? generationAssetKeys.has(assetKey) : false;
    const isTaskActive = assetKey && !shotGroupClipIds.has(action.id) ? activeTaskAssetKeys.has(assetKey) : false;

    return (
      <ClipAction
        action={action}
        clipMeta={clipMeta}
        isSelected={isClipSelected(action.id)}
        isPrimary={primaryClipId === action.id}
        selectedClipIds={[...selectedClipIds]}
        thumbnailSrc={thumbnailSrc}
        audioSrc={audioSrc}
        clipWidth={clipWidthPx}
        onSelect={handleClipSelect}
        onDoubleClickAsset={onDoubleClickAsset}
        onSplitHere={handleSplitClipHere}
        onSplitClipsAtPlayhead={handleSplitClipsAtPlayhead}
        onDeleteClips={handleDeleteClips}
        onDeleteClip={handleDeleteClip}
        onToggleMuteClips={handleToggleMuteClips}
        isTaskActive={isTaskActive}
        isVariantStale={isStale && !isDismissed}
        isGenerationAsset={isGenAsset}
        onUpdateVariant={isGenAsset && assetKey ? () => void updateAssetToCurrentVariant(assetKey) : undefined}
        onDismissStale={isStale && assetKey ? () => dismissAsset(assetKey) : undefined}
        canCreateShotFromSelection={selectionShotCreationState.canCreateShot}
        existingShots={existingShotsForSelection}
        onCreateShotFromSelection={handleCreateShotFromSelection}
        onGenerateVideoFromSelection={handleGenerateVideoFromSelection}
        onNavigateToShot={handleNavigateToShot}
        onOpenGenerateVideo={handleOpenGenerateVideo}
        isCreatingShot={isCreating}
      />
    );
  }, [
    selectionShotCreationState.canCreateShot,
    existingShotsForSelection,
    activeTaskAssetKeys,
    shotGroupClipIds,
    data,
    dismissAsset,
    dismissedAssetKeys,
    generationAssetKeys,
    handleCreateShotFromSelection,
    handleClipSelect,
    handleDeleteClip,
    handleDeleteClips,
    handleGenerateVideoFromSelection,
    handleNavigateToShot,
    handleOpenGenerateVideo,
    handleSplitClipHere,
    handleSplitClipsAtPlayhead,
    handleToggleMuteClips,
    isCreating,
    isClipSelected,
    onDoubleClickAsset,
    primaryClipId,
    resolvedClipMap,
    trackMap,
    selectedClipIds,
    staleAssetKeys,
    thumbnailMap,
    updateAssetToCurrentVariant,
  ]);

  const handleTrackDragEnd = useCallback(({ active, over }: DragEndEvent) => {
    if (!over) {
      return;
    }

    const activeSortableId = String(active.id);
    const overSortableId = String(over.id);
    if (
      activeSortableId === overSortableId ||
      !activeSortableId.startsWith('track-') ||
      !overSortableId.startsWith('track-')
    ) {
      return;
    }

    const activeTrackId = activeSortableId.slice('track-'.length);
    const overTrackId = overSortableId.slice('track-'.length);
    handleMoveTrack(activeTrackId, overTrackId);
  }, [handleMoveTrack]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full overflow-hidden rounded-xl border border-border bg-card/80">
      <div
        ref={timelineWrapperRef as React.RefObject<HTMLDivElement>}
        className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
        onDragOver={onTimelineDragOver}
        onDragLeave={onTimelineDragLeave}
        onDrop={onTimelineDrop}
      >
        <TimelineCanvas
          ref={timelineRef as React.RefObject<import('@/tools/video-editor/types/timeline-canvas').TimelineCanvasHandle>}
          {...({ staleShotGroupIds } as any)}
          rows={data.rows}
          tracks={data.tracks}
          scale={scale}
